//#region node_modules/algosdk/dist/esm/account.js
/**
* generateAccount returns a new Algorand address and its corresponding secret key
*/
function generateAccount() {
	const keys = keyPair();
	return {
		addr: new Address(keys.publicKey),
		sk: keys.secretKey
	};
}
